"""AddTags"""

import itertools
from typing import Literal

from qiskit.dagcircuit import DAGCircuit
from qiskit.transpiler.basepasses import TransformationPass

from ...aliases import CircuitInstruction
from ...annotations import InjectNoise, Tag, Twirl
from ...utils import BoxKey, get_annotation, undress_box, validate_literals


class AddTags(TransformationPass):
    """Inserts :class:`~.Tag` annotations to all box instructions.

    This pass finds all ``box`` nodes in the DAG and adds :class:`~.Tag` annotations to them.
    The tagging mode controls how ``ref`` strings are assigned:

    * ``'unique_box'``: the ``ref`` is a truncated hash of the box's structural content (i.e.
      ignoring single-qubit gate, and see :class:`~.BoxKey`), so structurally equivalent boxes share
      the same ``ref`` across circuits. Boxes with different :class:`~.Twirl` specifications are
      treated as unique, but all other annotations are ignored when comparing boxes.
    * ``'unique_instance'``: the ``ref`` is an incrementing counter (``t0``, ``t1``, ...),
      so every box in a circuit gets a unique ``ref``. The counter resets on each call to
      :meth:`run`.
    * ``'noise_ref'``: the ``ref`` is taken from the box's :class:`~.InjectNoise` annotation's
      ``ref`` field joined by an underscore with its ``modifier_ref`` field when present. Boxes
      without an :class:`~.InjectNoise` annotation are skipped.

    Args:
        mode: The tagging mode. ``'unique_box'`` assigns the same ref to structurally
            equivalent boxes; ``'unique_instance'`` assigns a unique ref to every box.
        overwrite: Whether to overwrite :class:`~.Tag` annotations that are already present
            in the circuit.
        prefix_ref: A prefix to all the ``ref`` strings generated by this class.
    """

    _BOX_KEYS: dict[tuple[BoxKey, str], str] = {}
    _REFS: set[str] = set()

    @validate_literals("mode")
    def __init__(
        self,
        mode: Literal["unique_box", "unique_instance", "noise_ref"] = "unique_box",
        overwrite: bool = False,
        prefix_ref: str = "t",
    ):
        super().__init__()
        self.mode = mode
        self.overwrite = overwrite
        self.prefix_ref = prefix_ref

    def _get_ref(self, box_key: BoxKey) -> str:
        cache_key = (box_key, self.prefix_ref)
        if cache_key in self._BOX_KEYS:
            return self._BOX_KEYS[cache_key]

        for key_length in range(3, 16):
            candidate = f"{self.prefix_ref}{box_key.hexdigest[:key_length]}"
            if candidate not in self._REFS:
                self._BOX_KEYS[cache_key] = candidate
                self._REFS.add(candidate)
                return candidate

        raise RuntimeError("Could not resolve box hash collision.")

    def run(self, dag: DAGCircuit) -> DAGCircuit:
        instance_counter = itertools.count()

        for node in dag.op_nodes():
            if node.op.name != "box":
                continue

            existing_tag = get_annotation(node.op, Tag)
            if existing_tag is not None and not self.overwrite:
                continue

            if self.mode == "unique_box":
                # mirror the AddInjectNoise convention for consistency.
                undressed_box = undress_box(node.op)
                twirl = get_annotation(node.op, Twirl)
                undressed_box.annotations = [twirl] if twirl is not None else []
                instr = CircuitInstruction(
                    undressed_box, undressed_box.body.qubits, undressed_box.body.clbits
                )
                ref = self._get_ref(BoxKey(instr))
            elif self.mode == "noise_ref":
                if (inject_noise := get_annotation(node.op, InjectNoise)) is None:
                    continue
                suffix = f"_{inject_noise.modifier_ref}" if inject_noise.modifier_ref else ""
                ref = f"{inject_noise.ref}{suffix}"
            else:
                # unique_instance: assign a fresh counter value per box per run()
                ref = f"{self.prefix_ref}{next(instance_counter)}"

            new_tag = Tag(ref=ref)
            if existing_tag is not None:
                annotation_idx = node.op.annotations.index(existing_tag)
                node.op.annotations[annotation_idx] = new_tag
            else:
                node.op.annotations += [new_tag]

            # Substitute back into the dag to guarantee that the
            # change makes it back to the rust data model.
            dag.substitute_node(node, node.op)

        return dag
